    updateAgent: {
        parameters: {
            query?: never;
            header?: never;
            path: {
                /** @description The ID of the agent. */
                agent_id: number;
            };
            cookie?: never;
        };
        requestBody: {
            content: {
                "application/json": components["schemas"]["AgentConfigInput"];
            };
        };
        responses: {
            /** @description Updated agent. */
            200: {
                headers: {
                    [name: string]: unknown;
                };
                content: {
                    /**
                     * @example {
                     *       "id": 6365,
                     *       "name": "Updated Support Agent",
                     *       "status": "Completed"
                     *     }
                     */
                    "application/json": {
                        /** @description Agent identifier. */
                        id?: number;
                        name?: string;
                        /** @description Build state of the agent after the update. Always `Completed` once the operation returns. */
                        status?: string;
                    };
                };
            };
        };
    };
    deleteAgent: {
        parameters: {
            query?: never;
            header?: never;
            path: {
                /** @description The ID of the agent. */
                agent_id: number;
            };
            cookie?: never;
        };
        requestBody?: never;
        responses: {
            /** @description Agent deleted. */
            200: {
                headers: {
                    [name: string]: unknown;
                };
                content: {
                    /**
                     * @example {
                     *       "success": true,
                     *       "message": "Agent deleted successfully"
                     *     }
                     */
                    "application/json": {
                        success?: boolean;
                        message?: string;
                    };
                };
            };
        };
    };
    dispatchCall: {
        parameters: {
            query?: never;
            header?: never;
            path?: never;
            cookie?: never;
        };
        requestBody: {
            content: {
                "application/json": {
                    /**
                     * @description The ID of the agent that will handle the call.
                     * @example 158910
                     */
                    agent_id: number;
                    /**
                     * @description The phone number to call. Must include country code (e.g., +15551234567).
                     * @example +15551234567
                     */
                    to_number: string;
                    /**
                     * @description The imported phone number id to call.
                     * @example 23
                     */
                    from_number_id?: number;
                    /**
                     * @description Optional context information as key-value pairs to be passed to the agent during the call. Can contain any custom fields relevant to your use case.
                     * @example {
                     *       "user_name": "Jane Doe",
                     *       "account_id": "A-2031",
                     *       "last_order": "2026-04-15"
                     *     }
                     */
                    call_context?: {
                        [key: string]: unknown;
                    };
                };
            };
        };
        responses: {
            /** @description Call dispatched. */
            200: {
                headers: {
                    [name: string]: unknown;
                };
                content: {
                    /**
                     * @example {
                     *       "success": true,
                     *       "status": "dispatched",
                     *       "requestId": 3166940,
                     *       "custom_variables_count": 1
                     *     }
                     */
                    "application/json": {
                        success?: boolean;
                        /**
                         * @description Dispatch state on the platform side. `dispatched` means the call has been queued for the dialer.
                         * @example dispatched
                         */
                        status?: string;
                        /**
                         * @description Internal call request id. Use it to correlate with `call_request_id` on `/calls/logs`.
                         * @example 3166940
                         */
                        requestId?: number;
                        /** @description Number of keys the platform extracted from `call_context`. */
                        custom_variables_count?: number;
                    };
                };
            };
        };
    };
